mapper.select:
SELECT
FROM mcp_gateway
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE mcp_gateway
SET status      = #{status},
    update_time = NOW(),
    version     = version + 1
WHERE gateway_id = #{gatewayId}
  AND version = #{oldVersion}

UPDATE mcp_gateway
gateway_id = #{gatewayId}, gateway_name = #{gatewayName}, gateway_description = #{gatewayDescription}, gateway_version = #{gatewayVersion}, status = #{status}, auth = #{auth}, update_time = NOW()
WHERE id = #{id}

UPDATE mcp_gateway
gateway_name = #{gatewayName}, gateway_description = #{gatewayDescription}, gateway_version = #{gatewayVersion}, status = #{status}, auth = #{auth}, update_time = NOW()
WHERE gateway_id = #{gatewayId}

